                      alignItems="center"
                      spacing={1.25}
                      flex={1}
                      sx={{ minWidth: 0 }}
                    >
                      <ImageOrAvatar
                        url={user.profile.presignedImageUrl}
                        width={36}
                        height={36}
                      />
                      <Box sx={{ minWidth: 0 }}>
                        <Typography
                          variant="subtitle1"
                          noWrap
                          sx={{
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                            opacity: _.first(user.givenUserRoles[teamId])
                              ?.deleteFlag
                              ? 0.5
                              : 1,
                          }}
                        >
                          {user.profile.username ?? '-'}
                        </Typography>
                        <Typography
                          variant="body2"
                          color="text.secondary"
                          noWrap
                          sx={{
                            overflow: 'hidden',
                            textOverflow: 'ellipsis',
                          }}
                        >
                          {user.email}
                        </Typography>
                      </Box>
                    </Stack>

                    {/* アクション（⋯ メニュー） */}
                    {hasManagementWriteAccess && (
                      <IconButton
                        size="small"
                        color="info"
                        onClick={(e) => {
                          if (_.isNil(anchorEl)) {
