                  </Stack>

                  {/* 共有メニュー（モバイルでも再利用） */}
                  {hasManagementWriteAccess && (
                    <Menu
                      onClose={closeMenu}
                      anchorEl={anchorEl}
                      open={selectedProfileId === user.id}
                    >
                      {_.first(user.givenUserRoles[teamId])?.deleteFlag &&
                      currentUser.id != user.id ? (
                        <>
                          <MenuItem
                            onClick={() => {
                              // banned and not the same user as currentUser
                              setUserToReactivate(user);
                              closeMenu();
                            }}
                          >
                            {translate('reactivate')}
                          </MenuItem>
                        </>
                      ) : (
                        ''
                      )}
                      {!_.first(user.givenUserRoles[teamId])?.deleteFlag ? (
                        <MenuItem
                          onClick={() => {
                            // not banned
                            setEditingUser(user);
                            closeMenu();
                          }}
                        >
                          {translate('edit')}
                        </MenuItem>
                      ) : (
                        ''
                      )}
                      {!_.first(user.givenUserRoles[teamId])?.deleteFlag &&
                      currentUser.id != user.id ? (
                        <>
                          <MenuItem
                            onClick={() => {
                              // not banned and not the same user as currentUser
                              setUserToDelete(user);
                              closeMenu();
                            }}
                          >
                            {translate('deactivate')}
                          </MenuItem>
                        </>
                      ) : (
                        ''
                      )}
                    </Menu>
                  )}
                </Paper>
              ))}
            </Stack>
          ) : (
            // ======== デスクトップ（md以上）：従来のテーブル ========
            <TableContainer
              component={Paper}
              sx={{
                mt: 2,
              }}
            >
                <Table
                  aria-label="a dense table"
                  sx={{
                    '.MuiTableCell-root': {
                      overflowWrap: 'anywhere',
                      px: 2,
                      py: 2,
                    },
                  }}
                >
                  <TableHead>
                    <TableRow>
                      <TableCell align="left">{translate('name')}</TableCell>
                      <TableCell align="left">{translate('email')}</TableCell>
                      <TableCell align="left">{translate('role')}</TableCell>
                      <TableCell align="left">{/* button */}</TableCell>
                    </TableRow>
                  </TableHead>
                  <TableBody>
                    {users.map((user) => (
                      <TableRow
                        key={user.id}
                        sx={{
                          '&:last-child td, &:last-child th': { border: 0 },
                          background: _.first(user.givenUserRoles[teamId])
                            ?.deleteFlag
                            ? 'darkgray'
                            : 'inherit',
                        }}
                      >
                        <TableCell align="left">
                          <Stack direction="row" alignItems="center" spacing={1}>
                            <ImageOrAvatar
                              url={user.profile.presignedImageUrl}
                              height={30}
                              width={30}
                            />
                            <Typography
                              sx={{
                                textDecoration: 'none',
                                color: 'text.primary',
                              }}
                              variant="inherit"
                            >
                              {user.profile.username ?? '-'}
                            </Typography>
                          </Stack>
                        </TableCell>
                        <TableCell align="left">{user.email}</TableCell>
                        <TableCell align="left">
                          <Stack direction="row" spacing={1}>
                            {_.first(user.givenUserRoles[teamId])?.deleteFlag ? (
                              <>{translate('deactivated')}</>
                            ) : (
                              <>
                                {_.map(
                                  user.givenUserRoles[teamId] ?? [],
                                  (userRole, idx) => {
                                    return (
                                      <Box key={idx}>
                                        {userRoleToDispName(
                                          userRole.roleGroup.name,
                                        ) ?? ''}
                                      </Box>
                                    );
                                  },
                                )}
                              </>
                            )}
                          </Stack>
                        </TableCell>
                        <TableCell align="right">
                          {hasManagementWriteAccess ? (
                            <>
                              <Button
                                color="neutral"
                                onClick={(e) => {
                                  if (_.isNil(anchorEl)) {
                                    openMenu(e, user);
                                  } else {
                                    closeMenu();
                                  }
                                }}
                              >
                                <MoreHoriz />
                              </Button>

                              <Menu
                                onClose={closeMenu}
                                anchorEl={anchorEl}
                                open={selectedProfileId === user.id}
                              >
                                {_.first(user.givenUserRoles[teamId])
                                  ?.deleteFlag && currentUser.id != user.id ? (
                                  <>
                                    <MenuItem
                                      onClick={() => {
                                        // banned and not the same user as currentUser
                                        setUserToReactivate(user);
                                        closeMenu();
                                      }}
                                    >
                                      {translate('reactivate')}
                                    </MenuItem>
                                  </>
                                ) : (
                                  ''
                                )}
                                {!_.first(user.givenUserRoles[teamId])
                                  ?.deleteFlag ? (
                                  <MenuItem
                                    onClick={() => {
                                      // not banned
                                      setEditingUser(user);
                                      closeMenu();
                                    }}
                                  >
                                    {translate('edit')}
                                  </MenuItem>
                                ) : (
                                  ''
                                )}
                                {!_.first(user.givenUserRoles[teamId])
                                  ?.deleteFlag && currentUser.id != user.id ? (
                                  <>
                                    <MenuItem
                                      onClick={() => {
                                        // not banned and not the same user as currentUser
                                        setUserToDelete(user);
                                        closeMenu();
                                      }}
                                    >
                                      {translate('deactivate')}
                                    </MenuItem>
                                  </>
                                ) : (
                                  ''
                                )}
                              </Menu>
                            </>
                          ) : (
                            ''
                          )}
                        </TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </TableContainer>

              {/* Mobile Card View */}
              <Stack
                spacing={2}
                sx={{ mt: 2, display: { xs: 'block', md: 'none' } }}
              >
                {users.map((user) => (
                  <Paper
                    key={user.id}
                    sx={{
                      p: 2,
                      background: _.first(user.givenUserRoles[teamId])
                        ?.deleteFlag
                        ? 'darkgray'
                        : 'inherit',
                    }}
                  >
                    <Stack spacing={1.5}>
                      {/* Name & Avatar */}
                      <Stack
                        direction="row"
                        alignItems="center"
                        justifyContent="space-between"
                      >
                        <Stack direction="row" alignItems="center" spacing={1}>
                          <ImageOrAvatar
                            url={user.profile.presignedImageUrl}
                            height={40}
                            width={40}
                          />
                          <Typography
                            variant="body1"
                            sx={{
                              fontWeight: 600,
                              color: 'text.primary',
